"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[8794],{1444(e){e.exports=JSON.parse('{"tag":{"label":"compute","permalink":"/gsf-patterns/tags/compute","allTagsPath":"/gsf-patterns/tags","count":24,"items":[{"id":"architecture/system-topology/containerize-your-workload-where-applicable","title":"Containerize your workloads","description":"Containerizing workloads enables better resource utilisation and bin packing, reducing unnecessary compute allocation and embodied carbon compared to running full virtual machines.","permalink":"/gsf-patterns/architecture/system-topology/containerize-your-workload-where-applicable"},{"id":"architecture/system-topology/implement-stateless-design","title":"Implement stateless design","description":"Service state refers to the in-memory or on-disk data required by a service to function. State includes the data structures and member variables that the service reads and writes. Depending on how the service is architected, the state might also include files or other resources stored on the disk. Applications that consume large memory or on-disk data require larger VM sizes, especially for cloud computing where you would need larger VM SKUs to support high RAM capacity and multiple data disks.","permalink":"/gsf-patterns/architecture/system-topology/implement-stateless-design"},{"id":"development/pre-trained-transfer-learning","title":"Leverage pre-trained models and transfer learning","description":"Fine-tune existing pre-trained models instead of training from scratch to dramatically reduce the compute, energy, and time required for model development.","permalink":"/gsf-patterns/development/pre-trained-transfer-learning"},{"id":"operations/capacity-management/match-utilization-requirements-of-vm","title":"Match utilization requirements of virtual machines (VMs)","description":"It\'s better to have one VM running at a higher utilization than two running at low utilization rates, not only in terms of energy proportionality but also in terms of embodied carbon. Two servers running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilized server could be more efficiently used for another task or process.","permalink":"/gsf-patterns/operations/capacity-management/match-utilization-requirements-of-vm"},{"id":"operations/capacity-management/match-utilization-requirements-with-pre-configured-server","title":"Match utilization requirements with pre-configured servers","description":"It\'s better to have one VM running at a higher utilization than two running at low utilization rates, not only in terms of energy proportionality but also in terms of embodied carbon. Two servers running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilized server could be more efficiently used for another task or process.","permalink":"/gsf-patterns/operations/capacity-management/match-utilization-requirements-with-pre-configured-server"},{"id":"development/web-performance/minimize-main-thread-work","title":"Minimize main thread work","description":"Long-running JavaScript on the browser\'s main thread underutilises multi-core CPUs; offloading heavy computations to Web Workers or server-side implementations reduces energy consumption and improves efficiency.","permalink":"/gsf-patterns/development/web-performance/minimize-main-thread-work"},{"id":"development/optimize-agent-orchestration-reduce-model-calls","title":"Optimize agent orchestration to reduce unnecessary model calls","description":"Design agentic AI workflows to minimise redundant model invocations and unnecessary compute through caching, conditional logic, and efficient orchestration patterns.","permalink":"/gsf-patterns/development/optimize-agent-orchestration-reduce-model-calls"},{"id":"operations/capacity-management/optimize-avg-cpu-utilization","title":"Optimize average CPU utilization","description":"CPU usage and utilization varies throughout the day, sometimes wildly for different computational requirements. The larger the variance between the average and peak CPU utilization values, the more resources need to be provisioned in stand-by mode to absorb those spikes in traffic.","permalink":"/gsf-patterns/operations/capacity-management/optimize-avg-cpu-utilization"},{"id":"operations/capacity-management/optimize-peak-cpu-utilization","title":"Optimize peak CPU utilization","description":"CPU usage and utilization varies throughout the day, sometimes wildly for different computational requirements. The larger the variance between the average and peak CPU utilization values, the more resources need to be provisioned in stand-by mode to absorb those spikes in traffic.","permalink":"/gsf-patterns/operations/capacity-management/optimize-peak-cpu-utilization"},{"id":"architecture/system-topology/reduce-network-traversal-between-VMs","title":"Reduce network traversal between VMs","description":"Placing VMs in the same region or availability zone minimises the physical distance data must travel between instances, reducing the energy consumed by network traversal.","permalink":"/gsf-patterns/architecture/system-topology/reduce-network-traversal-between-VMs"},{"id":"architecture/system-topology/run-ai-models-edge","title":"Run AI models at the edge","description":"Deploy AI inference on edge devices or local infrastructure to reduce data transfer, network energy use, and reliance on centralised cloud compute.","permalink":"/gsf-patterns/architecture/system-topology/run-ai-models-edge"},{"id":"operations/capacity-management/scale-infrastructure-with-user-load","title":"Scale infrastructure with user load","description":"Demand for resources depends on user load at any given time. However, most applications run without taking this into consideration. As a result,resources are underused and inefficient.","permalink":"/gsf-patterns/operations/capacity-management/scale-infrastructure-with-user-load"},{"id":"architecture/system-topology/scale-logical-components-independently","title":"Scale logical components independently","description":"Decomposing applications into independently scalable microservices allows each component to be right-sized for its own demand, reducing overall compute resource consumption and embodied carbon.","permalink":"/gsf-patterns/architecture/system-topology/scale-logical-components-independently"},{"id":"operations/scan-for-vulnerabilities","title":"Scan for vulnerabilities","description":"Many attacks on cloud infrastructure seek to misuse deployed resources, which leads to an unnecessary spike in usage and cost.","permalink":"/gsf-patterns/operations/scan-for-vulnerabilities"},{"id":"architecture/system-topology/efficient-hardware-ai-workloads","title":"Select efficient accelerators and instance types for AI workloads","description":"Match AI workloads to the most energy-efficient hardware accelerator or instance type to improve utilisation and reduce energy consumption per inference or training run.","permalink":"/gsf-patterns/architecture/system-topology/efficient-hardware-ai-workloads"},{"id":"development/select-efficient-ml-frameworks-inference-runtimes","title":"Select efficient ML frameworks and inference runtimes","description":"Choose ML frameworks and inference runtimes that best match your hardware and workload to reduce compute overhead and improve energy efficiency across training and production inference.","permalink":"/gsf-patterns/development/select-efficient-ml-frameworks-inference-runtimes"},{"id":"requirements/shed-lower-priority-traffic","title":"Shed lower priority traffic","description":"When resources are constrained during high-traffic events or when carbon intensity is high, more carbon emissions will be generated from your system. Adding more resources to support increased traffic requirements introduces more embodied carbon and more demand for electricity. Continuing to handle all requests during high carbon intensity will increase overall emissions for your system. Shedding traffic that is lower priority during these scenarios will save on resources and carbon emissions. This approach requires an understanding of your traffic, including which call requests are critical and which can best withstand retry attempts and failures.","permalink":"/gsf-patterns/requirements/shed-lower-priority-traffic"},{"id":"development/evaluate-whether-to-use-TLS-termination","title":"Terminate TLS at border gateway","description":"Transport Layer Security (TLS) ensures that all data passed between the web server and web browsers remain private and encrypted. However, terminating and re-establishing TLS increases CPU usage and might be unnecessary in certain architectures.","permalink":"/gsf-patterns/development/evaluate-whether-to-use-TLS-termination"},{"id":"operations/carbon-aware-ai-scheduling","title":"Use carbon-aware scheduling and region selection for AI workloads","description":"Reduce the carbon impact of AI workloads by running them in cloud regions with lower grid carbon intensity and scheduling deferrable jobs during periods of high renewable energy availability.","permalink":"/gsf-patterns/operations/carbon-aware-ai-scheduling"},{"id":"operations/capacity-management/use-circuit-breaker","title":"Use circuit breaker patterns","description":"Modern applications need to communicate with other applications on a regular basis. Since these other applications have their own deployment schedule, downtimes and availability, the network connection to these application might have problems. If the other application is not reachable, all network requests against this other application will fail and future network requests are futile.","permalink":"/gsf-patterns/operations/capacity-management/use-circuit-breaker"},{"id":"operations/use-cloud-native-network-security-tools-and-controls","title":"Use cloud native network security tools and controls","description":"Network and web application firewalls provide protection against most common attacks and load shedding bad bots. These tools help to remove unnecessary data transmission and reduce the burden on the cloud infrastructure, while also using lower bandwidth and less infrastructure.","permalink":"/gsf-patterns/operations/use-cloud-native-network-security-tools-and-controls"},{"id":"architecture/technology-selection/use-energy-efficient-hardware","title":"Use cloud native processor VMs","description":"Cloud VMs built on energy-efficient processors, such as ARM-based cloud-native chips, can run scale-out workloads with significantly lower energy consumption and embodied carbon than traditional alternatives.","permalink":"/gsf-patterns/architecture/technology-selection/use-energy-efficient-hardware"},{"id":"architecture/system-topology/on-demand-execution-ai-agent-workloads","title":"Use on-demand execution for AI and agent workloads","description":"Trigger AI and agent workloads only when needed using serverless or event-driven platforms to eliminate idle compute and reduce unnecessary energy consumption.","permalink":"/gsf-patterns/architecture/system-topology/on-demand-execution-ai-agent-workloads"},{"id":"development/right-sized-energy-efficient-ai-models","title":"Use right-sized and energy-efficient AI models","description":"Select and optimize AI models that are appropriately sized for the task to reduce compute, memory, and energy consumption during training and inference.","permalink":"/gsf-patterns/development/right-sized-energy-efficient-ai-models"}],"unlisted":false}}')}}]);